{"content":"package com.liseasons.event;

import com.liseasons.season.Season;
import java.util.Arrays;
import java.util.List;

/**
 * 季节事件类型枚举
 * 定义了 13 种季节事件类型及其所属季节
 */
public enum SeasonEventType {
    // 春季事件
    SPRING_BREEZE("微风习习", Season.SPRING),
    SPRING_COLD("春寒料峭", Season.SPRING),
    SPRING_RAIN("春雨绵绵", Season.SPRING),
    FAIR_WEATHER("风和日丽", Season.SPRING),

    // 夏季事件
    HOT_SUN("烈日炎炎", Season.SUMMER),
    HIGH_TEMPERATURE("炎热高温", Season.SUMMER),

    // 秋季事件
    AUTUMN_COOL("秋意渐凉", Season.AUTUMN),
    AUTUMN_RAIN("秋雨连绵", Season.AUTUMN),
    STORM("风暴来袭", Season.AUTUMN),

    // 冬季事件
    FREEZING_COLD("天寒地冻", Season.WINTER),
    BONE_CHILLING("寒冷刺骨", Season.WINTER),
    HEAVY_SNOW("大雪纷飞", Season.WINTER),
    SLEET("冻雨淅沥", Season.WINTER);

    private final String displayName;
    private final Season season;

    SeasonEventType(String displayName, Season season) {
        this.displayName = displayName;
        this.season = season;
    }

    public String getDisplayName() {
        return displayName;
    }

    public Season getSeason() {
        return season;
    }

    /**
     * 获取指定季节的所有事件类型
     */
    public static List<SeasonEventType> getBySeason(Season season) {
        return Arrays.stream(values())
                .filter(type -> type.season == season)
                .toList();
    }
}
