+
+import com.liseasons.climate.TemperatureMonitorService;
+import com.liseasons.climate.TemperatureService;
+import com.liseasons.climate.TemperatureSnapshot;
+import com.liseasons.config.ConfigManager;
+import com.liseasons.season.SeasonManager;
+import com.liseasons.season.SeasonState;
+import org.bukkit.Bukkit;
+import org.bukkit.entity.Player;
+import org.bukkit.plugin.java.JavaPlugin;
+
+import java.util.*;
+import java.util.concurrent.ConcurrentHashMap;
+
+/**
+ * 季节事件管理器
+ * 负责季节事件的触发、冷却、效果执行
+ */
+public class SeasonEventManager {
+    private final JavaPlugin plugin;
+    private final SeasonManager seasonManager;
+    private final TemperatureService temperatureService;
+    private final ConfigManager configManager;
+    
+    // 事件配置缓存
+    private final Map<String, SeasonEventConfig> eventConfigs = new ConcurrentHashMap<>();
+    
+    // 玩家事件冷却记录: playerId -> (eventId -> lastTriggerTime)
+    private final Map<UUID, Map<String, Long>> playerEventCooldowns = new ConcurrentHashMap<>();
+    
+    // 全局事件冷却时间（毫秒）
+    private long globalEventCooldown = 5000;
+    
+    // 玩家最后一次事件触发时间
+    private final Map<UUID, Long> playerLastEventTime = new ConcurrentHashMap<>();
+    
+    // 效果执行器
+    private final SeasonEventEffectExecutor effectExecutor;
+
+    public SeasonEventManager(
+            JavaPlugin plugin,
+            SeasonManager seasonManager,
+            TemperatureService temperatureService,
+            ConfigManager configManager
+    ) {
+        this.plugin = plugin;
+        this.seasonManager = seasonManager;
+        this.temperatureService = temperatureService;
+        this.configManager = configManager;
+        this.effectExecutor = new SeasonEventEffectExecutor(plugin);
+    }
+
+    /**
+     * 初始化事件配置
+     */
+    public void loadEventConfigs(List<SeasonEventConfig> configs) {
+        eventConfigs.clear();
+        for (SeasonEventConfig config : configs) {
+            eventConfigs.put(config.eventId(), config);
+        }
+    }
+
+    /**
+     * 检查并触发玩家的季节事件
+     */
+    public void checkAndTriggerEvents(Player player) {
+        UUID playerId = player.getUniqueId();
+        
+        // 检查全局冷却
+        long now = System.currentTimeMillis();
+        Long lastEventTime = playerLastEventTime.get(playerId);
+        if (lastEventTime != null && (now - lastEventTime) < globalEventCooldown) {
+            return;
+        }
+
+        // 获取玩家所在世界的季节状态
+        SeasonState seasonState = seasonManager.getState(player.getWorld());
+        if (seasonState == null) {
+            return;
+        }
+
+        // 获取玩家温度快照
+        TemperatureSnapshot snapshot = temperatureService.snapshot(player);
+
+        // 查找匹配的事件
+        List<SeasonEventConfig> matchingEvents = findMatchingEvents(seasonState, snapshot);
+        
+        if (matchingEvents.isEmpty()) {
+            return;
+        }
+
+        // 按优先级排序
+        matchingEvents.sort(Comparator.comparingInt(SeasonEventConfig::priority).reversed());
+
+        // 触发第一个匹配的事件
+        SeasonEventConfig eventConfig = matchingEvents.get(0);
+        
+        // 检查单个事件冷却
+        if (!isEventCooldownExpired(playerId, eventConfig.eventId(), now)) {
+            return;
+        }
+
+        // 创建事件上下文
+        SeasonEventContext context = new SeasonEventContext(
+                player,
+                seasonState,
+                snapshot,
+                now
+        );
+
+        // 执行事件效果
+        triggerEvent(player, eventConfig, context);
+
+        // 更新冷却时间
+        updateEventCooldown(playerId, eventConfig.eventId(), now);
+        playerLastEventTime.put(playerId, now);
+    }
+
+    /**
+     * 查找匹配的事件
+     */
+    private List<SeasonEventConfig> findMatchingEvents(SeasonState seasonState, TemperatureSnapshot snapshot) {
+        List<SeasonEventConfig> matching = new ArrayList<>();
+
+        for (SeasonEventConfig config : eventConfigs.values()) {
+            // 检查是否启用
+            if (!config.enabled()) {
+                continue;
+            }
+
+            // 检查季节是否匹配
+            if (!config.season().equals(seasonState.season())) {
+                continue;
+            }
+
+            // 检查温度是否满足触发条件
+            if (config.triggersAt(snapshot.value())) {
+                matching.add(config);
+            }
+        }
+
+        return matching;
+    }
+
+    /**
+     * 检查事件冷却是否已过期
+     */
+    private boolean isEventCooldownExpired(UUID playerId, String eventId, long now) {
+        Map<String, Long> cooldowns = playerEventCooldowns.get(playerId);
+        if (cooldowns == null) {
+            return true;
+        }
+
+        Long lastTriggerTime = cooldowns.get(eventId);
+        if (lastTriggerTime == null) {
+            return true;
+        }
+
+        SeasonEventConfig config = eventConfigs.get(eventId);
+        if (config == null) {
+            return true;
+        }
+
+        return (now - lastTriggerTime) >= config.cooldownMillis();
+    }
+
+    /**
+     * 更新事件冷却时间
+     */
+    private void updateEventCooldown(UUID playerId, String eventId, long now) {
+        playerEventCooldowns
+                .computeIfAbsent(playerId, k -> new ConcurrentHashMap<>())
+                .put(eventId, now);
+    }
+
+    /**
+     * 触发事件
+     */
+    private void triggerEvent(Player player, SeasonEventConfig eventConfig, SeasonEventContext context) {
+        // 执行所有效果
+        for (String effectId : eventConfig.effects()) {
+            effectExecutor.executeEffect(player, effectId, context);
+        }
+
+        // 发送事件通知
+        String message = String.format(
+                "§e[%s] §f%s 事件触发！体感温度: §c%.1f°C",
+                context.getSeasonName(),
+                eventConfig.getDisplayName(),
+                context.getBodyTemperature()
+        );
+        player.sendMessage(message);
+    }
+
+    /**
+     * 清理玩家数据（玩家离线时调用）
+     */
+    public void cleanupPlayer(UUID playerId) {
+        playerEventCooldowns.remove(playerId);
+        playerLastEventTime.remove(playerId);
+    }
+
+    /**
+     * 设置全局事件冷却时间
+     */
+    public void setGlobalEventCooldown(long cooldownMillis) {
+        this.globalEventCooldown = cooldownMillis;
+    }
+
+    /**
+     * 获取事件配置
+     */
+    public SeasonEventConfig getEventConfig(String eventId) {
+        return eventConfigs.get(eventId);
+    }
+
+    /**
+     * 获取所有事件配置
+     */
+    public Collection<SeasonEventConfig> getAllEventConfigs() {
+        return eventConfigs.values();
+    }
+}
","added_lines":224,"removed_lines":0,"approval_decision":"accept"},{"item_id":"1af9c424-8e78-4b02-8499-61e8690c4f16","session_id":"2df1b0a4-8693-4ee5-87e7-3f46bb54990a","tool_name":"create_file","change_kind":"add","status":"completed","file_path":"src/main/java/com/liseasons/event/SeasonEventEffectExecutor.java","diff":"+package com.liseasons.event;
+
+import org.bukkit.Particle;
+import org.bukkit.Sound;
+import org.bukkit.entity.Player;
+import org.bukkit.potion.PotionEffect;
+import org.bukkit.potion.PotionEffectType;
+import org.bukkit.plugin.java.JavaPlugin;
+
+/**
+ * 季节事件效果执行器
+ * 负责执行各种季节事件效果
+ */
+public class SeasonEventEffectExecutor {
+    private final JavaPlugin plugin;
+
+    public SeasonEventEffectExecutor(JavaPlugin plugin) {
+        this.plugin = plugin;
+    }
+
+    /**
+     * 执行效果
+     * 效果格式: TYPE:param1:param2:...
+     * 
+     * 支持的效果类型:
+     * - PARTICLE:particleType:amount:offsetX:offsetY:offsetZ
+     * - POTION:effectType:amplifier:duration
+     * - SOUND:soundType:volume:pitch
+     * - MESSAGE:message
+     * - SCREEN_FREEZE:ticks
+     * - DAMAGE:amount
+     */
+    public void executeEffect(Player player, String effectId, SeasonEventContext context) {
+        if (effectId == null || effectId.isEmpty()) {
+            return;
+        }
+
+        String[] parts = effectId.split(":");
+        if (parts.length == 0) {
+            return;
+        }
+
+        String effectType = parts[0].toUpperCase();
+
+        try {
+            switch (effectType) {
+                case "PARTICLE" -> executeParticleEffect(player, parts, context);
+                case "POTION" -> executePotionEffect(player, parts, context);
+                case "SOUND" -> executeSoundEffect(player, parts, context);
+                case "MESSAGE" -> executeMessageEffect(player, parts, context);
+                case "SCREEN_FREEZE" -> executeScreenFreezeEffect(player, parts, context);
+                case "DAMAGE" -> executeDamageEffect(player, parts, context);
+                case "HEAL" -> executeHealEffect(player, parts, context);
+                case "FIRE" -> executeFireEffect(player, parts, context);
+                default -> plugin.getLogger().warning("Unknown effect type: " + effectType);
+            }
+        } catch (Exception e) {
+            plugin.getLogger().warning("Error executing effect " + effectId + ": " + e.getMessage());
+        }
+    }
+
+    /**
+     * 执行粒子效果
+     * 格式: PARTICLE:particleType:amount:offsetX:offsetY:offsetZ
+     */
+    private void executeParticleEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 2) return;
+
+        try {
+            Particle particle = Particle.valueOf(parts[1].toUpperCase());
+            int amount = parts.length > 2 ? Integer.parseInt(parts[2]) : 10;
+            double offsetX = parts.length > 3 ? Double.parseDouble(parts[3]) : 0.5;
+            double offsetY = parts.length > 4 ? Double.parseDouble(parts[4]) : 0.5;
+            double offsetZ = parts.length > 5 ? Double.parseDouble(parts[5]) : 0.5;
+
+            player.getWorld().spawnParticle(
+                    particle,
+                    player.getLocation(),
+                    amount,
+                    offsetX, offsetY, offsetZ
+            );
+        } catch (IllegalArgumentException e) {
+            plugin.getLogger().warning("Invalid particle type: " + parts[1]);
+        }
+    }
+
+    /**
+     * 执行药水效果
+     * 格式: POTION:effectType:amplifier:duration
+     */
+    private void executePotionEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 4) return;
+
+        try {
+            PotionEffectType effectType = PotionEffectType.getByName(parts[1].toUpperCase());
+            if (effectType == null) {
+                plugin.getLogger().warning("Invalid potion effect type: " + parts[1]);
+                return;
+            }
+
+            int amplifier = Integer.parseInt(parts[2]);
+            int duration = Integer.parseInt(parts[3]) * 20; // 转换为 ticks
+
+            player.addPotionEffect(new PotionEffect(effectType, duration, amplifier, false, false));
+        } catch (NumberFormatException e) {
+            plugin.getLogger().warning("Invalid potion parameters: " + e.getMessage());
+        }
+    }
+
+    /**
+     * 执行声音效果
+     * 格式: SOUND:soundType:volume:pitch
+     */
+    private void executeSoundEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 2) return;
+
+        try {
+            Sound sound = Sound.valueOf(parts[1].toUpperCase());
+            float volume = parts.length > 2 ? Float.parseFloat(parts[2]) : 1.0f;
+            float pitch = parts.length > 3 ? Float.parseFloat(parts[3]) : 1.0f;
+
+            player.playSound(player.getLocation(), sound, volume, pitch);
+        } catch (IllegalArgumentException e) {
+            plugin.getLogger().warning("Invalid sound type: " + parts[1]);
+        }
+    }
+
+    /**
+     * 执行消息效果
+     * 格式: MESSAGE:message
+     */
+    private void executeMessageEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 2) return;
+
+        String message = String.join(":", java.util.Arrays.copyOfRange(parts, 1, parts.length));
+        // 替换占位符
+        message = message.replace("{season}", context.getSeasonName());
+        message = message.replace("{term}", context.getSolarTermName());
+        message = message.replace("{temperature}", String.format("%.1f", context.getBodyTemperature()));
+        message = message.replace("{air_temperature}", String.format("%.1f", context.getAirTemperature()));
+
+        player.sendMessage(message);
+    }
+
+    /**
+     * 执行冻屏效果
+     * 格式: SCREEN_FREEZE:ticks
+     */
+    private void executeScreenFreezeEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 2) return;
+
+        try {
+            int ticks = Integer.parseInt(parts[1]);
+            // 通过给予盲目效果来实现冻屏
+            player.addPotionEffect(new PotionEffect(
+                    PotionEffectType.BLINDNESS,
+                    ticks,
+                    0,
+                    false,
+                    false
+            ));
+        } catch (NumberFormatException e) {
+            plugin.getLogger().warning("Invalid screen freeze duration: " + parts[1]);
+        }
+    }
+
+    /**
+     * 执行伤害效果
+     * 格式: DAMAGE:amount
+     */
+    private void executeDamageEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 2) return;
+
+        try {
+            double damage = Double.parseDouble(parts[1]);
+            player.damage(damage);
+        } catch (NumberFormatException e) {
+            plugin.getLogger().warning("Invalid damage amount: " + parts[1]);
+        }
+    }
+
+    /**
+     * 执行治疗效果
+     * 格式: HEAL:amount
+     */
+    private void executeHealEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 2) return;
+
+        try {
+            double heal = Double.parseDouble(parts[1]);
+            double newHealth = Math.min(player.getHealth() + heal, player.getMaxHealth());
+            player.setHealth(newHealth);
+        } catch (NumberFormatException e) {
+            plugin.getLogger().warning("Invalid heal amount: " + parts[1]);
+        }
+    }
+
+    /**
+     * 执行着火效果
+     * 格式: FIRE:seconds
+     */
+    private void executeFireEffect(Player player, String[] parts, SeasonEventContext context) {
+        if (parts.length < 2) return;
+
+        try {
+            int seconds = Integer.parseInt(parts[1]);
+            player.setFireTicks(seconds * 20);
+        } catch (NumberFormatException e) {
+            plugin.getLogger().warning("Invalid fire duration: " + parts[1]);
+        }
+    }
+}
