+public enum FestivalType {
+    // 中国传统节日 (13个)
+    SPRING_FESTIVAL("春节", MonthDay.of(1, 1), FestivalCategory.TRADITIONAL),
+    LANTERN_FESTIVAL("元宵节", MonthDay.of(1, 15), FestivalCategory.TRADITIONAL),
+    DRAGON_BOAT_FESTIVAL("龙抬头", MonthDay.of(2, 2), FestivalCategory.TRADITIONAL),
+    SHANGSI_FESTIVAL("上巳节", MonthDay.of(3, 3), FestivalCategory.TRADITIONAL),
+    QINGMING_FESTIVAL("清明节", MonthDay.of(4, 5), FestivalCategory.TRADITIONAL),
+    DRAGON_BOAT_HOLIDAY("端午节", MonthDay.of(5, 5), FestivalCategory.TRADITIONAL),
+    QIXI_FESTIVAL("七夕节", MonthDay.of(7, 7), FestivalCategory.TRADITIONAL),
+    ZHONGYUAN_FESTIVAL("中元节", MonthDay.of(7, 15), FestivalCategory.TRADITIONAL),
+    MID_AUTUMN_FESTIVAL("中秋节", MonthDay.of(8, 15), FestivalCategory.TRADITIONAL),
+    CHONGYANG_FESTIVAL("重阳节", MonthDay.of(9, 9), FestivalCategory.TRADITIONAL),
+    LABA_FESTIVAL("腊八节", MonthDay.of(12, 8), FestivalCategory.TRADITIONAL),
+    XIAONIAN("小年", MonthDay.of(12, 23), FestivalCategory.TRADITIONAL),
+    CHUXI("除夕", MonthDay.of(12, 30), FestivalCategory.TRADITIONAL),
+
+    // 法定节假日 (7个)
+    NEW_YEAR("元旦", MonthDay.of(1, 1), FestivalCategory.LEGAL_HOLIDAY),
+    SPRING_FESTIVAL_HOLIDAY("春节假期", MonthDay.of(1, 1), FestivalCategory.LEGAL_HOLIDAY),
+    QINGMING_HOLIDAY("清明假期", MonthDay.of(4, 5), FestivalCategory.LEGAL_HOLIDAY),
+    LABOR_DAY("劳动节", MonthDay.of(5, 1), FestivalCategory.LEGAL_HOLIDAY),
+    DRAGON_BOAT_HOLIDAY_LEGAL("端午假期", MonthDay.of(5, 5), FestivalCategory.LEGAL_HOLIDAY),
+    MID_AUTUMN_HOLIDAY("中秋假期", MonthDay.of(8, 15), FestivalCategory.LEGAL_HOLIDAY),
+    NATIONAL_DAY("国庆节", MonthDay.of(10, 1), FestivalCategory.LEGAL_HOLIDAY),
+
+    // 常见公历节日 (9个)
+    VALENTINES_DAY("情人节", MonthDay.of(2, 14), FestivalCategory.GREGORIAN),
+    WOMENS_DAY("妇女节", MonthDay.of(3, 8), FestivalCategory.GREGORIAN),
+    TREE_PLANTING_DAY("植树节", MonthDay.of(3, 12), FestivalCategory.GREGORIAN),
+    FOOLS_DAY("愚人节", MonthDay.of(4, 1), FestivalCategory.GREGORIAN),
+    YOUTH_DAY("青年节", MonthDay.of(5, 4), FestivalCategory.GREGORIAN),
+    CHILDRENS_DAY("儿童节", MonthDay.of(6, 1), FestivalCategory.GREGORIAN),
+    TEACHERS_DAY("教师节", MonthDay.of(9, 10), FestivalCategory.GREGORIAN),
+    HALLOWEEN("万圣节", MonthDay.of(10, 31), FestivalCategory.GREGORIAN),
