 public final class ConfigManager {
     private final LISeasonsPlugin plugin;
     private PluginConfig pluginConfig;

     public ConfigManager(LISeasonsPlugin plugin) {
         this.plugin = plugin;
         this.pluginConfig = load();
     }

     public PluginConfig reload() {
         this.plugin.reloadConfig();
         this.plugin.reloadMessagesConfig();
         this.pluginConfig = load();
         return this.pluginConfig;
     }

     public PluginConfig getConfig() {
         return this.pluginConfig;
     }

     private PluginConfig load() {
         Map<Season, Integer> seasonDurations = new EnumMap<>(Season.class);
         for (Season season : Season.values()) {
             int value = this.plugin.getConfig().getInt("time.season-duration-days." + season.key(), 24);
             seasonDurations.put(season, Math.max(1, value));
         }

         Map<Season, MonthDay> seasonStartDates = new EnumMap<>(Season.class);
         seasonStartDates.put(Season.SPRING, parseMonthDay(this.plugin.getConfig().getString("time.season-start-dates.spring"), MonthDay.of(3, 4)));
