+package com.liseasons.config;
+
+import com.liseasons.event.SeasonEventConfig;
+import com.liseasons.event.SeasonEventType;
+import com.liseasons.season.Season;
+import org.bukkit.configuration.ConfigurationSection;
+
+import java.util.ArrayList;
+import java.util.List;
+
+/**
+ * 季节事件配置加载器
+ */
+public class SeasonEventConfigLoader {
+    
+    /**
+     * 从配置文件加载季节事件配置
+     */
+    public static List<SeasonEventConfig> loadSeasonEvents(ConfigurationSection config) {
+        List<SeasonEventConfig> events = new ArrayList<>();
+        
+        if (config == null) {
+            return events;
+        }
+
+        // 加载春季事件
+        loadSeasonEventsByType(config, "spring-events", events);
+        
+        // 加载夏季事件
+        loadSeasonEventsByType(config, "summer-events", events);
+        
+        // 加载秋季事件
+        loadSeasonEventsByType(config, "autumn-events", events);
+        
+        // 加载冬季事件
+        loadSeasonEventsByType(config, "winter-events", events);
+
+        return events;
+    }
+
+    /**
+     * 加载指定季节的事件
+     */
+    private static void loadSeasonEventsByType(
+            ConfigurationSection config,
+            String seasonKey,
+            List<SeasonEventConfig> events
+    ) {
+        ConfigurationSection seasonSection = config.getConfigurationSection(seasonKey);
+        if (seasonSection == null) {
+            return;
+        }
+
+        for (String eventKey : seasonSection.getKeys(false)) {
+            ConfigurationSection eventSection = seasonSection.getConfigurationSection(eventKey);
+            if (eventSection == null) {
+                continue;
+            }
+
+            try {
+                SeasonEventConfig eventConfig = loadSingleEvent(eventKey, eventSection);
+                if (eventConfig != null) {
+                    events.add(eventConfig);
+                }
+            } catch (Exception e) {
+                System.err.println("Failed to load season event: " + eventKey + " - " + e.getMessage());
+            }
+        }
+    }
+
+    /**
+     * 加载单个事件配置
+     */
+    private static SeasonEventConfig loadSingleEvent(String eventId, ConfigurationSection section) {
+        String typeStr = section.getString("type");
+        if (typeStr == null) {
+            throw new IllegalArgumentException("Event type not specified");
+        }
+
+        SeasonEventType type = SeasonEventType.valueOf(typeStr);
+        Season season = type.getSeason();
+
+        double triggerTemperature = section.getDouble("trigger-temperature", 0.0);
+        String triggerMode = section.getString("trigger-mode", "above");
+        double triggerTemperatureMax = section.getDouble("trigger-temperature-max", triggerTemperature);
+        int priority = section.getInt("priority", 0);
+        long cooldownSeconds = section.getLong("cooldown-seconds", 30);
+        boolean enabled = section.getBoolean("enabled", true);
+
+        List<String> effects = section.getStringList("effects");
+        if (effects == null) {
+            effects = new ArrayList<>();
+        }
+
+        return new SeasonEventConfig(
+                eventId,
+                type,
+                season,
+                triggerTemperature,
+                triggerMode,
+                triggerTemperatureMax,
+                priority,
+                cooldownSeconds * 1000L,
+                effects,
+                enabled
+        );
+    }
+}

+package com.liseasons.config;
+
+import com.liseasons.festival.FestivalConfig;
+import com.liseasons.festival.FestivalType;
+import org.bukkit.configuration.ConfigurationSection;
+
+import java.time.MonthDay;
+import java.util.ArrayList;
+import java.util.List;
+
+/**
+ * 节日配置加载器
+ */
+public class FestivalConfigLoader {
+    
+    /**
+     * 从配置文件加载节日配置
+     */
+    public static List<FestivalConfig> loadFestivals(ConfigurationSection config) {
+        List<FestivalConfig> festivals = new ArrayList<>();
+        
+        if (config == null) {
+            return festivals;
+        }
+
+        // 加载传统节日
+        loadFestivalsByCategory(config, "traditional-festivals", festivals);
+        
+        // 加载法定节假日
+        loadFestivalsByCategory(config, "legal-holidays", festivals);
+        
+        // 加载公历节日
+        loadFestivalsByCategory(config, "gregorian-festivals", festivals);
+
+        return festivals;
+    }
+
+    /**
+     * 加载指定分类的节日
+     */
+    private static void loadFestivalsByCategory(
+            ConfigurationSection config,
+            String categoryKey,
+            List<FestivalConfig> festivals
+    ) {
+        ConfigurationSection categorySection = config.getConfigurationSection(categoryKey);
+        if (categorySection == null) {
+            return;
+        }
+
+        for (String festivalKey : categorySection.getKeys(false)) {
+            ConfigurationSection festivalSection = categorySection.getConfigurationSection(festivalKey);
+            if (festivalSection == null) {
+                continue;
+            }
+
+            try {
+                FestivalConfig festivalConfig = loadSingleFestival(festivalKey, festivalSection);
+                if (festivalConfig != null) {
+                    festivals.add(festivalConfig);
+                }
+            } catch (Exception e) {
+                System.err.println("Failed to load festival: " + festivalKey + " - " + e.getMessage());
+            }
+        }
+    }
+
+    /**
+     * 加载单个节日配置
+     */
+    private static FestivalConfig loadSingleFestival(String festivalId, ConfigurationSection section) {
+        String typeStr = section.getString("type");
+        if (typeStr == null) {
+            throw new IllegalArgumentException("Festival type not specified");
+        }
+
+        FestivalType type = FestivalType.valueOf(typeStr);
+        
+        String dateStr = section.getString("date");
+        if (dateStr == null) {
+            throw new IllegalArgumentException("Festival date not specified");
+        }
+
+        // 解析日期格式 "MM-dd"
+        String[] dateParts = dateStr.split("-");
+        if (dateParts.length != 2) {
+            throw new IllegalArgumentException("Invalid date format: " + dateStr);
+        }
+
+        int month = Integer.parseInt(dateParts[0]);
+        int day = Integer.parseInt(dateParts[1]);
+        MonthDay date = MonthDay.of(month, day);
+
+        String displayName = section.getString("display-name", type.getDisplayName());
+        String categoryStr = section.getString("category", "TRADITIONAL");
+        FestivalType.FestivalCategory category = FestivalType.FestivalCategory.valueOf(categoryStr);
+        
+        int priority = section.getInt("priority", 0);
+        boolean enabled = section.getBoolean("enabled", true);
+
+        return new FestivalConfig(
+                festivalId,
+                type,
+                date,
+                displayName,
+                category,
+                enabled,
+                priority
+        );
+    }
+}

