         seasonBaseTemperatures.put(Season.AUTUMN, temperatureFile.getDouble("season-base-temperature.autumn", 18.0D));
         seasonBaseTemperatures.put(Season.WINTER, temperatureFile.getDouble("season-base-temperature.winter", 2.0D));
         Map<Season, TemperatureRangeConfig> seasonBaseRanges = loadSeasonBaseRanges(temperatureFile);
         Map<String, Double> solarTermModifiers = loadDoubleSection(temperatureFile, "solar-term-modifier");
         solarTermModifiers.remove("enable");

         Map<String, Double> biomeOverrides = loadDoubleSection(temperatureFile, "biome-overrides");
