{"content":"package com.liseasons.festival;

import org.junit.jupiter.api.Test;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * 节日系统单元测试
 */
public class FestivalManagerTest {

    @Test
    public void testFestivalTypeEnumeration() {
        // 验证所有29个节日都已定义
        FestivalType[] types = FestivalType.values();
        assertEquals(29, types.length, "应该有29个节日");
    }

    @Test
    public void testTraditionalFestivals() {
        // 验证传统节日数量
        List<FestivalType> traditional = FestivalType.getByCategory(FestivalCategory.TRADITIONAL);
        assertEquals(13, traditional.size(), "应该有13个传统节日");

        // 验证所有传统节日的分类
        assertTrue(traditional.stream().allMatch(f -> f.getCategory() == FestivalCategory.TRADITIONAL),
                "所有传统节日的分类应该是TRADITIONAL");
    }

    @Test
    public void testLegalHolidays() {
        // 验证法定节假日数量
        List<FestivalType> legal = FestivalType.getByCategory(FestivalCategory.LEGAL);
        assertEquals(7, legal.size(), "应该有7个法定节假日");

        // 验证所有法定节假日的分类
        assertTrue(legal.stream().allMatch(f -> f.getCategory() == FestivalCategory.LEGAL),
                "所有法定节假日的分类应该是LEGAL");
    }

    @Test
    public void testGregorianFestivals() {
        // 验证公历节日数量
        List<FestivalType> gregorian = FestivalType.getByCategory(FestivalCategory.GREGORIAN);
        assertEquals(9, gregorian.size(), "应该有9个公历节日");

        // 验证所有公历节日的分类
        assertTrue(gregorian.stream().allMatch(f -> f.getCategory() == FestivalCategory.GREGORIAN),
                "所有公历节日的分类应该是GREGORIAN");
    }

    @Test
    public void testFestivalDisplayNames() {
        // 验证节日显示名称
        assertEquals("春节", FestivalType.SPRING_FESTIVAL.getDisplayName());
        assertEquals("元宵节", FestivalType.LANTERN_FESTIVAL.getDisplayName());
        assertEquals("清明节", FestivalType.QINGMING_FESTIVAL.getDisplayName());
        assertEquals("端午节", FestivalType.DRAGON_FESTIVAL.getDisplayName());
        assertEquals("中秋节", FestivalType.MID_AUTUMN_FESTIVAL.getDisplayName());
        assertEquals("圣诞节", FestivalType.CHRISTMAS.getDisplayName());
    }

    @Test
    public void testFestivalDates() {
        // 验证节日日期格式
        for (FestivalType festival : FestivalType.values()) {
            String date = festival.getLunarDate();
            assertNotNull(date, "节日日期不应该为null");
            assertTrue(date.matches("\\d{2}-\\d{2}"), "节日日期格式应该是MM-DD");
        }
    }

    @Test
    public void testSpecificFestivalDates() {
        // 验证特定节日的日期
        assertEquals("01-01", FestivalType.SPRING_FESTIVAL.getLunarDate(), "春节应该是01-01");
        assertEquals("01-15", FestivalType.LANTERN_FESTIVAL.getLunarDate(), "元宵节应该是01-15");
        assertEquals("05-05", FestivalType.DRAGON_FESTIVAL.getLunarDate(), "端午节应该是05-05");
        assertEquals("08-15", FestivalType.MID_AUTUMN_FESTIVAL.getLunarDate(), "中秋节应该是08-15");
        assertEquals("12-25", FestivalType.CHRISTMAS.getLunarDate(), "圣诞节应该是12-25");
    }

    @Test
    public void testFestivalCategoryDistribution() {
        // 验证节日分类总数
        int total = FestivalType.getByCategory(FestivalCategory.TRADITIONAL).size()
                + FestivalType.getByCategory(FestivalCategory.LEGAL).size()
                + FestivalType.getByCategory(FestivalCategory.GREGORIAN).size();

        assertEquals(29, total, "所有分类的节日总数应该是29");
    }

    @Test
    public void testFestivalCategoryNames() {
        // 验证节日分类名称
        assertEquals("传统节日", FestivalCategory.TRADITIONAL.getDisplayName());
        assertEquals("法定节假日", FestivalCategory.LEGAL.getDisplayName());
        assertEquals("公历节日", FestivalCategory.GREGORIAN.getDisplayName());
    }

    @Test
    public void testNoFestivalDuplicates() {
        // 验证没有重复的节日
        FestivalType[] types = FestivalType.values();
        for (int i = 0; i < types.length; i++) {
            for (int j = i + 1; j < types.length; j++) {
                assertNotEquals(types[i], types[j], "不应该有重复的节日");
            }
        }
    }

    @Test
    public void testAllFestivalsHaveDisplayNames() {
        // 验证所有节日都有显示名称
        for (FestivalType festival : FestivalType.values()) {
            assertNotNull(festival.getDisplayName(), "节日应该有显示名称");
            assertFalse(festival.getDisplayName().isEmpty(), "节日显示名称不应该为空");
        }
    }

    @Test
    public void testAllFestivalsHaveCategories() {
        // 验证所有节日都有分类
        for (FestivalType festival : FestivalType.values()) {
            assertNotNull(festival.getCategory(), "节日应该有分类");
        }
    }
}
