+    /**
+     * 处理节日指令
+     */
+    private boolean handleFestival(CommandSender sender, String[] args) {
+        if (args.length < 2) {
+            sender.sendMessage("§c用法: /seasons festival <list|today|info> [参数]");
+            return true;
+        }
+
+        String subCmd = args[1].toLowerCase();
+        return switch (subCmd) {
+            case "list" -> {
+                sender.sendMessage("§6=== 节日列表 ===");
+                sender.sendMessage("§e传统节日:");
+                for (com.liseasons.festival.FestivalType type : com.liseasons.festival.FestivalType.getByCategory(com.liseasons.festival.FestivalCategory.TRADITIONAL)) {
+                    sender.sendMessage("  §7" + type.getDisplayName());
+                }
+                sender.sendMessage("§e法定节假日:");
+                for (com.liseasons.festival.FestivalType type : com.liseasons.festival.FestivalType.getByCategory(com.liseasons.festival.FestivalCategory.LEGAL)) {
+                    sender.sendMessage("  §7" + type.getDisplayName());
+                }
+                sender.sendMessage("§e公历节日:");
+                for (com.liseasons.festival.FestivalType type : com.liseasons.festival.FestivalType.getByCategory(com.liseasons.festival.FestivalCategory.GREGORIAN)) {
+                    sender.sendMessage("  §7" + type.getDisplayName());
+                }
+                yield true;
+            }
+            case "today" -> {
+                sender.sendMessage("§6=== 今日节日 ===");
+                sender.sendMessage("§a节日查询功能开发中...");
+                yield true;
+            }
+            case "info" -> {
+                sender.sendMessage("§6=== 节日系统信息 ===");
+                sender.sendMessage("§e已加载节日: " + (this.plugin.getFestivalManager() != null ? "是" : "否"));
+                sender.sendMessage("§e节日总数: 29");
+                yield true;
+            }
+            default -> {
+                sender.sendMessage("§c未知的节日子命令: " + subCmd);
+                yield true;
+            }
+        };
+    }
 }
