                 messages.rawMessageList("calendar.lore-visual", MessageManager.Placeholder.of("visual", describeVisuals(state)))
         ), 16);
         fill(inventory, createInfoItem(
                 Material.COMPASS,
                 messages.rawMessage("calendar.month-item"),
                 messages.rawMessageList(
                         "calendar.lore-month",
