     private int sizeFor(CalendarPage page) {
         int configured = this.plugin.getLiConfig().calendarConfig().size();
         return Math.max(configured, 54);
     }

     private List<SolarTerm> termsForMonth(int month) {
         return this.plugin.getLiConfig().gregorianDates().entrySet().stream()
                 .filter(entry -> entry.getValue().getMonthValue() == month)
                 .sorted(Comparator.comparingInt(entry -> entry.getValue().getDayOfMonth()))
                 .map(java.util.Map.Entry::getKey)
                 .toList();
     }

     private String describeMonthTerms(int month, MessageManager messages) {
         List<String> names = new ArrayList<>();
         for (SolarTerm term : termsForMonth(month)) {
             names.add(messages.solarTermName(term.key()));
         }
         return String.join("、", names);
     }

     private String formatMonthDay(SolarTerm term) {
         MonthDay date = this.plugin.getLiConfig().gregorianDates().getOrDefault(term, term.defaultDate());
         return date.getMonthValue() + "月" + date.getDayOfMonth() + "日";
     }

     private Material materialFor(SolarTerm term) {
         return materialFor(term.season());
     }

     private Material materialFor(Season season) {
         return switch (season) {
             case SPRING -> Material.FLOWERING_AZALEA;
             case SUMMER -> Material.SUNFLOWER;
             case AUTUMN -> Material.ACACIA_LEAVES;
             case WINTER -> Material.SNOWBALL;
         };
     }

     private String describeWeather(SeasonState state) {
         return switch (state.season()) {
             case SPRING -> "冰雪开始融化，气温回升，降雨略多。";
             case SUMMER -> "烈日偏强，作物生长更快，热带区域更容易出现干热感。";
             case AUTUMN -> "天气转凉，降雨趋缓，树叶和草地会逐步偏暖色。";
             case WINTER -> "降水减少，寒冷区域更容易落雪，露天静水会逐步结冰。";
         };
     }

     private String describeVisuals(SeasonState state) {
         return switch (state.season()) {
             case SPRING -> "草地转鲜绿，冰雪逐步退去，夜晚偶尔出现柔和萤光。";
             case SUMMER -> "草木颜色更浓，热带视觉更干燥，橡树偶尔掉落苹果。";
             case AUTUMN -> "桦树、针叶林和樱花树叶会分批染成暖橙色。";
             case WINTER -> "玩家周围群系会向雪原色调刷新，树冠会出现雪花和积雪效果。";
         };
     }

     private String pageName(MessageManager messages, CalendarPage page) {
         return switch (page) {
             case OVERVIEW -> plainText(messages.rawMessage("calendar.page-overview"));
             case MONTH_TERMS -> plainText(messages.rawMessage("calendar.page-month"));
             case YEAR_TERMS -> plainText(messages.rawMessage("calendar.page-year"));
             case TEMPERATURE -> plainText(messages.rawMessage("calendar.page-temperature"));
         };
     }

     private String plainText(Component component) {
         return net.kyori.adventure.text.serializer.plain.PlainTextComponentSerializer.plainText().serialize(component);
     }

     private String formatWetness(double wetness) {
         return Math.round(Math.max(0.0D, Math.min(1.0D, wetness)) * 100.0D) + "%";
     }

     private void renderSeasonEventsPage(Inventory inventory, MessageManager messages, SeasonState state, Player player) {
         // 获取当前季节的所有事件
         List<com.liseasons.event.SeasonEventConfig> seasonEvents = this.plugin.getSeasonEventManager()
                 .getAllEventConfigs().stream()
                 .filter(config -> config.season() == state.season() && config.enabled())
                 .sorted(Comparator.comparingInt(com.liseasons.event.SeasonEventConfig::priority).reversed())
                 .toList();

         // 标题物品
         fill(inventory, createInfoItem(
                 Material.BLAZE_ROD,
                 messages.rawMessage("calendar.season-events-title"),
                 messages.rawMessageList(
                         "calendar.lore-season-events-title",
                         MessageManager.Placeholder.of("season", messages.seasonName(state.season().key())),
                         MessageManager.Placeholder.of("count", String.valueOf(seasonEvents.size()))
                 )
         ), 4);

         // 显示事件列表
         int[] slots = {10, 11, 12, 13, 14, 15, 16, 19, 20, 21, 22, 23, 24, 25, 28, 29, 30, 31, 32, 33, 34};
         int index = 0;
         for (com.liseasons.event.SeasonEventConfig event : seasonEvents) {
             if (index >= slots.length) break;

             Material material = materialForEventType(event.type());
             List<Component> lore = new ArrayList<>();
             lore.add(messages.rawMessage("calendar.event-type", MessageManager.Placeholder.of("type", event.type().getDisplayName())));
             lore.add(messages.rawMessage("calendar.event-trigger", MessageManager.Placeholder.of("trigger", formatTriggerMode(event))));
             lore.add(messages.rawMessage("calendar.event-priority", MessageManager.Placeholder.of("priority", String.valueOf(event.priority()))));
             lore.add(messages.rawMessage("calendar.event-cooldown", MessageManager.Placeholder.of("cooldown", String.valueOf(event.cooldownMillis() / 1000))));
             lore.add(Component.text(""));
             lore.add(messages.rawMessage("calendar.event-effects-title"));
             for (String effect : event.effects()) {
                 lore.add(messages.rawMessage("calendar.event-effect-item", MessageManager.Placeholder.of("effect", effect)));
             }

             fill(inventory, createInfoItem(
                     material,
                     messages.rawMessage("calendar.event-item", MessageManager.Placeholder.of("event", event.type().getDisplayName())),
                     lore
             ), slots[index++]);
         }

         // 说明物品
         fill(inventory, createInfoItem(
                 Material.BOOK,
                 messages.rawMessage("calendar.season-events-guide"),
                 messages.rawMessageList("calendar.lore-season-events-guide")
         ), 40);
     }

     private void renderFestivalsPage(Inventory inventory, MessageManager messages, LocalDate today) {
         // 获取本月的所有节日
         List<com.liseasons.festival.FestivalConfig> monthFestivals = this.plugin.getFestivalManager()
                 .getMonthFestivals(today.getMonthValue());

         // 标题物品
         fill(inventory, createInfoItem(
                 Material.CAKE,
                 messages.rawMessage("calendar.festivals-title"),
                 messages.rawMessageList(
                         "calendar.lore-festivals-title",
                         MessageManager.Placeholder.of("month", today.getMonth().getDisplayName(TextStyle.FULL, Locale.CHINA)),
                         MessageManager.Placeholder.of("count", String.valueOf(monthFestivals.size()))
                 )
         ), 4);

         // 显示节日列表
         int[] slots = {10, 11, 12, 13, 14, 15, 16, 19, 20, 21, 22, 23, 24, 25, 28, 29, 30, 31, 32, 33, 34};
         int index = 0;
         for (com.liseasons.festival.FestivalConfig festival : monthFestivals) {
             if (index >= slots.length) break;

             Material material = materialForFestivalCategory(festival.category());
             MonthDay festivalDate = festival.date();
             boolean isToday = festivalDate.getMonthValue() == today.getMonthValue() && 
                             festivalDate.getDayOfMonth() == today.getDayOfMonth();

             List<Component> lore = new ArrayList<>();
             lore.add(messages.rawMessage("calendar.festival-date", 
                     MessageManager.Placeholder.of("date", festivalDate.getMonthValue() + "月" + festivalDate.getDayOfMonth() + "日")));
             lore.add(messages.rawMessage("calendar.festival-category", 
                     MessageManager.Placeholder.of("category", festival.getCategoryName())));
             if (isToday) {
                 lore.add(messages.rawMessage("calendar.festival-today"));
             }

             fill(inventory, createInfoItem(
                     isToday ? Material.ENCHANTED_BOOK : material,
                     messages.rawMessage("calendar.festival-item", MessageManager.Placeholder.of("festival", festival.getDisplayName())),
                     lore
             ), slots[index++]);
         }

         // 分类筛选按钮
         fill(inventory, createInfoItem(
                 Material.EMERALD,
                 messages.rawMessage("calendar.festivals-traditional"),
                 messages.rawMessageList("calendar.lore-festivals-traditional")
         ), 37);

         fill(inventory, createInfoItem(
                 Material.GOLD_INGOT,
                 messages.rawMessage("calendar.festivals-legal"),
                 messages.rawMessageList("calendar.lore-festivals-legal")
         ), 38);

         fill(inventory, createInfoItem(
                 Material.DIAMOND,
                 messages.rawMessage("calendar.festivals-gregorian"),
                 messages.rawMessageList("calendar.lore-festivals-gregorian")
         ), 39);

         // 说明物品
         fill(inventory, createInfoItem(
                 Material.BOOK,
                 messages.rawMessage("calendar.festivals-guide"),
                 messages.rawMessageList("calendar.lore-festivals-guide")
         ), 40);
     }

     private Material materialForEventType(com.liseasons.event.SeasonEventType type) {
         return switch (type.getSeason()) {
             case SPRING -> Material.CHERRY_LEAVES;
             case SUMMER -> Material.FIRE_CHARGE;
             case AUTUMN -> Material.ORANGE_DYE;
             case WINTER -> Material.SNOWBALL;
         };
     }

     private Material materialForFestivalCategory(com.liseasons.festival.FestivalType.FestivalCategory category) {
         return switch (category) {
             case TRADITIONAL -> Material.EMERALD;
             case LEGAL -> Material.GOLD_INGOT;
             case GREGORIAN -> Material.DIAMOND;
         };
     }

     private String formatTriggerMode(com.liseasons.event.SeasonEventConfig event) {
         return switch (event.triggerMode()) {
             case "above" -> "温度 ≥ " + event.triggerTemperature() + "°C";
             case "below" -> "温度 ≤ " + event.triggerTemperature() + "°C";
             case "range" -> "温度 " + event.triggerTemperature() + "°C ~ " + event.triggerTemperatureMax() + "°C";
             default -> "未知触发条件";
         };
     }
